"""Voronoi-guided Lloyd's algorithm for circle packing n=26 in unit square"""
import numpy as np
from scipy.spatial import Voronoi

def construct_packing():
    """
    Use Voronoi diagram and Lloyd's algorithm for structure-guided optimization.
    Voronoi cells define maximum extent for each circle.
    Lloyd relaxation moves centers toward cell centroids for better packing.
    """
    n = 26
    centers = _init_hexagonal(n)
    best_sum, best_centers, best_radii = 0, None, None

    for it in range(200):
        centers = np.clip(centers, 0.02, 0.98)

        # Add far boundary points to ensure bounded Voronoi cells
        all_points = _add_boundary_points(centers)

        try:
            vor = Voronoi(all_points)
        except:
            continue

        # Lloyd relaxation with decreasing step
        step = 0.35 * (0.985 ** it)
        new_centers = centers.copy()

        for i in range(n):
            poly = _get_clipped_cell(vor, i)
            if poly is not None and len(poly) >= 3:
                centroid = _polygon_centroid(poly)
                new_centers[i] += step * (centroid - centers[i])

        centers = np.clip(new_centers, 0.02, 0.98)

        # Compute radii based on distances
        radii = _compute_radii(centers)
        total = np.sum(radii)

        if total > best_sum:
            best_sum = total
            best_centers = centers.copy()
            best_radii = radii.copy()

    if best_centers is not None:
        best_radii = _compute_radii(best_centers)
        return best_centers, best_radii, np.sum(best_radii)
    else:
        centers = _init_hexagonal(n)
        radii = _compute_radii(centers)
        return centers, radii, np.sum(radii)


def _init_hexagonal(n):
    """Initialize with hexagonal-like pattern for 26 circles."""
    centers = []
    rows = [5, 4, 5, 4, 5, 3]
    y_spacing = 0.85 / (len(rows) - 1)
    for row, cnt in enumerate(rows):
        y = 0.075 + row * y_spacing
        x_spacing = 0.85 / (cnt - 1) if cnt > 1 else 0
        x_start = 0.075 if row % 2 == 0 else 0.075 + x_spacing / 2
        for j in range(cnt):
            x = x_start + j * x_spacing
            centers.append([x, y])
    return np.array(centers)


def _add_boundary_points(centers):
    """Add points far outside domain to bound Voronoi cells."""
    far = 10.0
    extra = [[-far, -far], [-far, far], [far, -far], [far, far],
             [-far, 0.5], [far, 0.5], [0.5, -far], [0.5, far]]
    return np.vstack([centers, extra])


def _get_clipped_cell(vor, idx):
    """Get Voronoi cell polygon clipped to unit square."""
    region_idx = vor.point_region[idx]
    region = vor.regions[region_idx]

    if -1 in region or len(region) < 3:
        return None

    vertices = vor.vertices[region]
    return _clip_to_square(vertices)


def _clip_to_square(vertices):
    """Clip polygon to unit square [0,1] x [0,1] using Sutherland-Hodgman."""
    poly = list(vertices)

    for (axis, val, keep_above) in [(0, 0, True), (0, 1, False), 
                                    (1, 0, True), (1, 1, False)]:
        if len(poly) < 3:
            return None
        new_poly = []
        for i in range(len(poly)):
            curr, prev = poly[i], poly[i - 1]
            curr_inside = curr[axis] >= val if keep_above else curr[axis] <= val
            prev_inside = prev[axis] >= val if keep_above else prev[axis] <= val

            if curr_inside:
                if not prev_inside:
                    t = (val - prev[axis]) / (curr[axis] - prev[axis] + 1e-10)
                    new_poly.append(prev + t * (curr - prev))
                new_poly.append(curr)
            elif prev_inside:
                t = (val - prev[axis]) / (curr[axis] - prev[axis] + 1e-10)
                new_poly.append(prev + t * (curr - prev))
        poly = new_poly

    return np.array(poly) if len(poly) >= 3 else None


def _polygon_centroid(vertices):
    """Compute centroid of polygon using shoelace formula."""
    n = len(vertices)
    area, cx, cy = 0, 0, 0
    for i in range(n):
        j = (i + 1) % n
        cross = vertices[i, 0] * vertices[j, 1] - vertices[j, 0] * vertices[i, 1]
        area += cross
        cx += (vertices[i, 0] + vertices[j, 0]) * cross
        cy += (vertices[i, 1] + vertices[j, 1]) * cross
    area *= 0.5
    if abs(area) < 1e-10:
        return np.mean(vertices, axis=0)
    return np.array([cx / (6 * area), cy / (6 * area)])


def _compute_radii(centers):
    """Compute maximum valid radii for all circles."""
    n = len(centers)
    radii = np.array([min(c[0], c[1], 1-c[0], 1-c[1]) for c in centers])

    for _ in range(100):
        ok = True
        for i in range(n):
            for j in range(i + 1, n):
                d = np.linalg.norm(centers[i] - centers[j])
                if radii[i] + radii[j] > d:
                    scale = d / (radii[i] + radii[j]) * 0.9999
                    radii[i] *= scale
                    radii[j] *= scale
                    ok = False
        if ok:
            break

    for _ in range(200):
        expanded = False
        for i in range(n):
            max_r = min(centers[i, 0], centers[i, 1], 1-centers[i, 0], 1-centers[i, 1])
            for j in range(n):
                if i != j:
                    d = np.linalg.norm(centers[i] - centers[j])
                    max_r = min(max_r, d - radii[j])
            if max_r > radii[i] + 1e-8:
                radii[i] = max_r * 0.9999
                expanded = True
        if not expanded:
            break

    return radii
